import base64
from PyQt5.QtGui import QPixmap, QIcon

# Base64-for Icon32.ico
Icon32_ico = ''''''
def get_embedded_icon():
    """Return QIcon with ICO format."""
    icon = QIcon()
    data = base64.b64decode(Icon32_ico)
    pix = QPixmap()
    pix.loadFromData(data, "ICO")
    icon.addPixmap(pix)
    return icon
